class Solution {
public:
void mergeSort(int arr[], int l, int r) {
    if (l < r) {
        int m = l + (r - l) / 2;
        mergeSort(arr, l, m);
        mergeSort(arr, m + 1, r);
        merge(arr, l, m, r);
    }
}

void Solution::merge(int arr[], int l, int m, int r) {
    int i = l;
    int j = m + 1;
    int k = l - 1;
    int[] temp = new int[r - l + 1];
    while (i <= m && j <= r) {
        if (arr[i] <= arr[j]) {
            temp[k--] = arr[i++];
        } else {
            temp[k--] = arr[j++];
        }
    }
    while (i <= m) {
        temp[k--] = arr[i++];
    }
    while (j <= r) {
        temp[k--] = arr[j++];
    }
    for (i = l; i <= r; i++) {
        arr[i] = temp[i - l];
    }
}
};

