class Solution:
    def mergeSort(self, arr: list[int], l: int, r: int) -> None:
        if l < r:
            m = l + (r - l) // 2
            self.mergeSort(arr, l, m)
            self.mergeSort(arr, m + 1, r)
            self.merge(arr, l, m, r)

    def Solution.merge(self, arr: list[int], l: int, m: int, r: int) -> None:
        i = l
        j = m + 1
        k = l - 1
        temp = [0] * (r - l + 1)
        while i <= m and j <= r:
            if arr[i] <= arr[j]:
                temp[k] = arr[i]
                k -= 1
                i += 1
            else:
                temp[k] = arr[j]
                k -= 1
                j += 1
        while i <= m:
            temp[k] = arr[i]
            k -= 1
            i += 1
        while j <= r:
            temp[k] = arr[j]
            k -= 1
            j += 1
        for i in range(l, r + 1):
            arr[i] = temp[i - l]

